using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Modules.EDocuments.Application.Services;namespace verii_metivon_api.Modules.EDocuments.Api;[ApiController,Authorize,Route("api/e-documents")]public sealed class EDocumentsController(IEDocumentService s):ControllerBase{[HttpGet]public async Task<IActionResult>List([FromQuery]EDocumentQuery q,CancellationToken ct){var r=await s.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpPost]public async Task<IActionResult>Create(CreateEDocumentRequest x,CancellationToken ct){var r=await s.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/queue")]public async Task<IActionResult>Queue(long id,CancellationToken ct){var r=await s.QueueAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpPost("provider-configuration")]public async Task<IActionResult>Provider(SaveProviderConfigurationRequest x,CancellationToken ct){var r=await s.SaveProviderAsync(x,ct);return StatusCode(r.StatusCode,r);}}
